final:
module gray_counter (
    input clk,
    input rst,
    output reg [3:0] gray
);
    reg [3:0] binary;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst) begin
            binary <= 4'b0000;
            gray <= 4'b0000;
        end else begin
            binary <= binary + 1;
            gray <= (binary >> 1) ^ binary;
        end
    end
endmodule
